// PUT /api/users/:userId - Update user profile
router.put('/api/users/:userId', async (req, res) => {
  try {
    const requestedUserId = parseInt(req.params.userId);
    const authenticatedUserId = req.user.id;
    const authenticatedUserRole = req.user.role;

    if (isNaN(requestedUserId)) {
      return res.status(400).json({ error: 'Invalid user ID' });
    }

    // Allowlist of fields regular users can update
    const userAllowedFields = ['first_name', 'last_name', 'profile_picture', 'bio'];
    
    // Allowlist of additional fields admins can update
    const adminAllowedFields = ['username', 'email', 'verified_status', 'account_type'];

    let user;
    let allowedFields;
    let updateData = {};

    if (authenticatedUserRole === 'admin') {
      // Admin can update any user
      user = await db.getUserByIdAdmin(requestedUserId);
      allowedFields = [...userAllowedFields, ...adminAllowedFields];
    } else {
      // Regular users can only update their own profile
      user = await db.getUserById(requestedUserId, authenticatedUserId);
      allowedFields = userAllowedFields;
    }

    if (!user) {
      return res.status(404).json({ error: 'User not found or access denied' });
    }

    // Object-level authorization check
    if (authenticatedUserRole !== 'admin' && user.id !== authenticatedUserId) {
      return res.status(403).json({ error: 'Access denied' });
    }

    // Filter input to only allowed fields (allowlist approach)
    for (const field of allowedFields) {
      if (req.body.hasOwnProperty(field)) {
        updateData[field] = req.body[field];
      }
    }

    // Explicitly reject privileged fields from client input
    const privilegedFields = ['role', 'credits', 'verified_status', 'account_type', 'is_admin', 'permissions'];
    for (const field of privilegedFields) {
      if (req.body.hasOwnProperty(field) && authenticatedUserRole !== 'admin') {
        return res.status(403).json({ error: 'Cannot update privileged fields' });
      }
    }

    if (Object.keys(updateData).length === 0) {
      return res.status(400).json({ error: 'No valid fields to update' });
    }

    // Perform update with scope enforcement
    if (authenticatedUserRole === 'admin') {
      await db.updateUserAdmin(requestedUserId, updateData);
    } else {
      await db.updateUser(requestedUserId, authenticatedUserId, updateData);
    }

    res.json({ message: 'User updated successfully', updated: updateData });
  } catch (error) {
    res.status(500).json({ error: 'Internal server error' });
  }
});

